                <>
                  <p className="font-medium">No events match this view.</p>
                  <p className="mt-1 text-sm text-muted-foreground">
                    Adjust the resource filters or create a new event to start
                    filling the schedule.
                  </p>
                </>
              )}
            </div>
          </div>
        ) : null}
      </div>
      {isHydrated ? createPortal(portals, document.body) : null}
      <p
        aria-live="polite"
        className="sr-only"
        data-testid="calendar-live-announcement"
      >
        {liveAnnouncement}
      </p>
    </div>
  )
}

function getCalendarSurfaceShadowClassName(surfaceShadow: "none" | "sm" | "md") {
  if (surfaceShadow === "sm") {
    return "shadow-[0_12px_36px_-24px_rgba(15,23,42,0.28)]"
  }

  if (surfaceShadow === "md") {
    return "shadow-[0_20px_80px_-48px_rgba(15,23,42,0.55)]"
  }

  return undefined
}

function getPreviewOccurrence(
  activeDrag: CalendarDragData,
  target: CalendarDropTarget,
  slotDuration: number,
  dragOffsetMinutes = 0
) {
  if (activeDrag.kind === "event") {
    const operation = getMoveOperation(
      activeDrag.occurrence,
      target,
      activeDrag.variant === "time-grid" ? dragOffsetMinutes : 0
    )

    return {
      ...activeDrag.occurrence,
      start: operation.nextStart,
      end: operation.nextEnd,
      allDay: operation.allDay ?? activeDrag.occurrence.allDay,
    }
  }

  const operation = getResizeOperation(
    activeDrag.occurrence,
    activeDrag.edge,
    target,
    slotDuration
  )

  return {
    ...activeDrag.occurrence,
    start: operation.nextStart,
    end: operation.nextEnd,
  }
}

function getMoveOperation(
  occurrence: CalendarOccurrence,
  target: CalendarDropTarget,
  dragOffsetMinutes = 0
): CalendarMoveOperation {
  const durationMs = occurrence.end.getTime() - occurrence.start.getTime()
  let nextStart: Date
  let nextEnd: Date
  let allDay = occurrence.allDay

  if (target.kind === "slot") {
    const durationMinutes = Math.max(1, Math.round(durationMs / 60_000))
    const latestStartMinute = Math.max(
      0,
      1_440 - Math.min(durationMinutes, 1_440)
    )
    const nextStartMinute = Math.min(
      latestStartMinute,
      Math.max(0, target.minuteOfDay - dragOffsetMinutes)
    )

    nextStart = setMinuteOfDay(startOfDay(target.day), nextStartMinute)
    nextEnd = new Date(nextStart.getTime() + durationMs)
    allDay = false
  } else {
    allDay = target.kind === "all-day" || occurrence.allDay

    if (allDay) {
      nextStart = startOfDay(target.day)
      nextEnd = addDays(nextStart, getDaySpan(occurrence))
    } else {
      nextStart = copyTimeParts(startOfDay(target.day), occurrence.start)
      nextEnd = new Date(nextStart.getTime() + durationMs)
    }
  }

  return {
    occurrence,
    nextStart,
    nextEnd,
    previousStart: occurrence.start,
    previousEnd: occurrence.end,
    allDay,
  }
}

function getDragOffsetMinutes(
  dragData: CalendarDragData,
  dragRect: DOMRect | null,
  clientY: number
) {
  if (
    dragData.kind !== "event" ||
    dragData.variant !== "time-grid" ||
    dragData.occurrence.allDay ||
    !dragRect ||
    dragRect.height <= 0
  ) {
    return 0
  }

  const durationMinutes = Math.max(
    1,
    Math.round(
      (dragData.occurrence.end.getTime() - dragData.occurrence.start.getTime()) /
        60_000
    )
  )
  const pointerOffsetY = Math.min(
    dragRect.height,
    Math.max(0, clientY - dragRect.top)
  )

  return Math.min(
    Math.max(0, durationMinutes - 1),
    Math.round((pointerOffsetY / dragRect.height) * durationMinutes)
  )
}

function getResizeOperation(
  occurrence: CalendarOccurrence,
  edge: "start" | "end",
  target: CalendarDropTarget,
  slotDuration: number
): CalendarResizeOperation {
  const rawDate =
    target.kind === "slot"
      ? setMinuteOfDay(startOfDay(target.day), target.minuteOfDay)
      : startOfDay(target.day)

  if (edge === "start") {
    return {
      occurrence,
      edge,
      nextStart: clampResize(rawDate, occurrence.end, "start", slotDuration),
      nextEnd: occurrence.end,
      previousStart: occurrence.start,
      previousEnd: occurrence.end,
    }
  }

  const adjustedEnd =
    target.kind === "slot" ? addMinutes(rawDate, slotDuration) : addDays(rawDate, 1)

  return {
    occurrence,
    edge,
    nextStart: occurrence.start,
    nextEnd: clampResize(adjustedEnd, occurrence.start, "end", slotDuration),
    previousStart: occurrence.start,
    previousEnd: occurrence.end,
  }
}

function areDropTargetsEqual(
  left: CalendarDropTarget | null,
  right: CalendarDropTarget | null
) {
  if (left === right) {
    return true
  }

  if (!left || !right || left.kind !== right.kind) {
    return false
  }

  if (left.day.getTime() !== right.day.getTime()) {
    return false
  }

  if (left.kind === "slot" && right.kind === "slot") {
    return left.minuteOfDay === right.minuteOfDay
  }

  return true
}

function getPointerDistance(
  startClientX: number,
  startClientY: number,
  currentClientX: number,
  currentClientY: number
) {
  return Math.hypot(currentClientX - startClientX, currentClientY - startClientY)
}

function getDragOverlayStyle(
  dragRect: DOMRect | null,
  interaction: ActiveDragInteraction | null
): React.CSSProperties | undefined {
  if (!dragRect || !interaction) {
    return undefined
  }

  return {
    height: dragRect.height,
    left: dragRect.left + interaction.currentClientX - interaction.initialClientX,
    position: "fixed",
    top: dragRect.top + interaction.currentClientY - interaction.initialClientY,
    width: dragRect.width,
  }
}

function getCalendarDropTargetFromPoint(
  clientX: number,
  clientY: number
): CalendarDropTarget | null {
  if (typeof document === "undefined") {
    return null
  }

  const match = document
    .elementsFromPoint(clientX, clientY)
    .find((element): element is HTMLElement => {
      return (
        element instanceof HTMLElement &&
        !!element.dataset.calendarDropTargetKind
      )
    })

  if (!match) {
    return null
  }

  const kind = match.dataset.calendarDropTargetKind
  const dayValue = match.dataset.calendarDropTargetDay

  if (!kind || !dayValue) {
    return null
  }

  const day = new Date(dayValue)

  if (Number.isNaN(day.getTime())) {
    return null
  }

  if (kind === "slot") {
    const minuteValue = match.dataset.calendarDropTargetMinute
    const minuteOfDay = Number(minuteValue)

    if (minuteValue === undefined || !Number.isFinite(minuteOfDay)) {
      return null
    }

    return {
      kind,
      day,
      minuteOfDay,
    }
  }

  if (kind === "day" || kind === "all-day") {
    return {
      kind,
      day,
    }
  }

  return null
}

function getTimeGridDropTargetFromPoint(
  clientX: number,
  clientY: number
): CalendarDropTarget | null {
  const target = getCalendarDropTargetFromPoint(clientX, clientY)

  return target?.kind === "slot" ? target : null
}

"use client"

import type { ComponentProps, ComponentType } from "react"

import {
  CaretLeftIcon,
  CaretRightIcon,
  ColumnsIcon,
  ListBulletsIcon,
  PlusIcon,
  RowsIcon,
  SquaresFourIcon,
} from "@phosphor-icons/react"

import { cn } from "@/lib/utils"

import { type CalendarView } from "../../types"
import { getCalendarSlotClassName } from "../../utils"
import type { CalendarToolbarProps } from "../shared"

const viewLabels: Record<CalendarView, string> = {
  month: "Month",
  week: "Week",
  day: "Day",
  agenda: "Agenda",
}

const viewIcons: Record<CalendarView, ComponentType<{ className?: string }>> = {
  month: SquaresFourIcon,
  week: ColumnsIcon,
  day: RowsIcon,
  agenda: ListBulletsIcon,
}

function ToolbarButton({
  className,
  size = "sm",
  tone = "ghost",
  ...props
}: ComponentProps<"button"> & {
  size?: "icon-sm" | "sm"
  tone?: "default" | "ghost" | "outline" | "secondary"
}) {
  return (
    <button
      className={cn(
        "inline-flex shrink-0 items-center justify-center rounded-[min(var(--radius-md),10px)] border text-sm font-medium whitespace-nowrap transition-colors outline-none focus-visible:border-ring focus-visible:ring-3 focus-visible:ring-ring/40 disabled:pointer-events-none disabled:opacity-50",
        size === "icon-sm" ? "size-8" : "h-8 gap-1 px-2.5",
        tone === "default"
          ? "border-transparent bg-primary text-primary-foreground hover:bg-primary/90"
          : "",
        tone === "ghost"
          ? "border-transparent bg-transparent hover:bg-muted hover:text-foreground"
          : "",
        tone === "outline"
          ? "border-border bg-background text-foreground shadow-xs hover:bg-muted"
          : "",
        tone === "secondary"
          ? "border-transparent bg-secondary text-secondary-foreground hover:bg-secondary/80"
          : "",
        className
      )}
      type="button"
      {...props}
    />
  )
}

export function CalendarToolbar({
  activeResourceIds,
  availableViews,
  classNames,
  currentLabel,
  density = "comfortable",
  onNavigate,
  onQuickCreate,
  onResourceFilterChange,
  onToday,
  onViewChange,
  renderToolbarExtras,
  resources,
  secondaryTimeZone,
  showSecondaryTimeZone,
  timeZone,
  view,
}: CalendarToolbarProps) {
  const visibleResourceCount = activeResourceIds.length || resources?.length || 0
  const hasResourceFilters = Boolean(
    resources &&
      resources.length > 1 &&
      onResourceFilterChange
  )
  const allResourceIds = resources?.map((resource) => resource.id) ?? []
  const allResourcesSelected =
    !resources?.length ||
    activeResourceIds.length === 0 ||
    activeResourceIds.length === allResourceIds.length
  const toolbarExtras = renderToolbarExtras?.({
    activeResourceIds,
    availableViews,
    resources: resources ?? [],
    view,
  })
  const showViewSwitcher = availableViews.length > 1

  return (
    <div
      className={getCalendarSlotClassName(
        classNames,
        "toolbar",
        cn(
          "flex flex-col border-b border-border/70 md:px-5",
          density === "compact" ? "gap-3 px-4 py-3" : "gap-4 px-4 py-4"
        )
      )}
    >
      <div className="flex flex-col gap-3 lg:flex-row lg:items-center lg:justify-between">
        <div className="flex min-w-0 flex-wrap items-start gap-2 sm:items-center">
          <div className="flex shrink-0 items-center gap-2">
            <ToolbarButton
              aria-label="Previous range"
              data-testid="calendar-nav-previous"
              onClick={() => onNavigate(-1)}
              size="icon-sm"
              tone="ghost"
            >
              <CaretLeftIcon className="size-4" />
            </ToolbarButton>
            <ToolbarButton
              aria-label="Next range"
              data-testid="calendar-nav-next"
              onClick={() => onNavigate(1)}
              size="icon-sm"
              tone="ghost"
            >
              <CaretRightIcon className="size-4" />
            </ToolbarButton>
            <ToolbarButton
              data-testid="calendar-nav-today"
              onClick={onToday}
              size="sm"
              tone="outline"
            >
              Today
            </ToolbarButton>
          </div>
          <div className="min-w-0 basis-full pt-1 sm:ml-2 sm:basis-auto sm:pt-0">
            <p
              className={getCalendarSlotClassName(
                classNames,
                "toolbarTitle",
                "truncate text-base font-medium tracking-tight md:text-lg"
              )}
              data-testid="calendar-current-label"
            >
              {currentLabel}
            </p>
            <p className="truncate text-xs text-muted-foreground">
              {timeZone ? `${timeZone} timezone` : "Local timezone"}
              {showSecondaryTimeZone && secondaryTimeZone
                ? ` · Secondary ${secondaryTimeZone}`
                : ""}
              {resources?.length
                ? ` · ${visibleResourceCount}/${resources.length} calendars`
                : ""}
            </p>
          </div>
        </div>
        <div
          className={getCalendarSlotClassName(
            classNames,
            "toolbarGroup",
            "flex flex-wrap items-center gap-2"
          )}
        >
          {showViewSwitcher ? (
            <div
              className={getCalendarSlotClassName(
                classNames,
                "viewSwitcher",
                "grid w-full grid-cols-2 gap-1 rounded-[1.35rem] border border-border/70 bg-muted/40 p-1.5 sm:flex sm:w-auto sm:flex-wrap sm:items-center sm:gap-1 sm:rounded-full sm:p-1"
              )}
            >
              {availableViews.map((item) => {
                const Icon = viewIcons[item]

                return (
                  <ToolbarButton
                    key={item}
                    className={getCalendarSlotClassName(
                      classNames,
                      "viewButton",
                      "w-full justify-center rounded-xl sm:w-auto sm:rounded-full"
                    )}
                    data-testid={`calendar-view-${item}`}
                    onClick={() => onViewChange(item)}
                    size="sm"
                    tone={view === item ? "secondary" : "ghost"}
                  >
                    <Icon className="size-4" />
                    {viewLabels[item]}
                  </ToolbarButton>
                )
              })}
            </div>
          ) : null}
          {onQuickCreate ? (
            <ToolbarButton
              data-testid="calendar-toolbar-create"
              onClick={onQuickCreate}
              size="sm"
              tone="default"
            >
              <PlusIcon className="size-4" />
              New event
            </ToolbarButton>
          ) : null}
        </div>
      </div>
      {hasResourceFilters || toolbarExtras ? (
        <div className="flex flex-col gap-3 lg:flex-row lg:items-center lg:justify-between">
          {hasResourceFilters ? (
            <div className="flex flex-wrap gap-2">
              <ToolbarButton
                onClick={() => onResourceFilterChange?.(allResourceIds)}
                size="sm"
                tone={allResourcesSelected ? "secondary" : "ghost"}
              >
                All calendars
              </ToolbarButton>
              {resources?.map((resource) => {
                const active = activeResourceIds.includes(resource.id)

                return (
                  <ToolbarButton
                    key={resource.id}
                    onClick={() => {
                      if (!onResourceFilterChange) {
                        return
                      }

                      const nextSelection = active
                        ? activeResourceIds.filter((id) => id !== resource.id)
                        : [...activeResourceIds, resource.id]

                      onResourceFilterChange(
                        nextSelection.length > 0 ? nextSelection : allResourceIds
                      )
                    }}
                    size="sm"
                    tone={active ? "secondary" : "ghost"}
                  >
                    <span
                      aria-hidden
                      className="size-2 rounded-full"
                      style={{ backgroundColor: resource.color }}
                    />
                    {resource.label}
                  </ToolbarButton>
                )
              })}
            </div>
          ) : (
            <span />
          )}
          {toolbarExtras ? (
            <div className="flex flex-wrap items-center gap-2">
              {toolbarExtras}
            </div>
          ) : null}
        </div>
      ) : null}
    </div>
  )
}

"use client"

import * as React from "react"

import { isSameDay, startOfDay } from "date-fns"

import { cn } from "@/lib/utils"

import type {
  CalendarClassNames,
  CalendarCreateDraft,
  CalendarEventRenderer,
  CalendarOccurrence,
} from "../../types"
import {
  formatHourLabel,
  formatDurationLabel,
  formatEventTimeLabel,
  formatMonthDayLabel,
  formatWeekday,
  getBlockedSegmentsForDay,
  getAllDayEvents,
  getBusinessHourSegmentsForDay,
  getCalendarSlotClassName,
  getDayLayout,
  getEventMetaLabel,
  getNextVisibleDay,
  getOutsideBusinessHourSegmentsForDay,
  getWeekDays,
  isToday,
  parseTimeStringToMinuteOfDay,
  setMinuteOfDay,
} from "../../utils"
import {
  CalendarEventCard,
  getResolvedAccentColor,
} from "./event-card"
import {
  type CalendarEventMenuPosition,
  type SharedViewProps,
  type TimeGridViewProps,
} from "../shared"

type FocusedTimeSlot = {
  dayIndex: number
  minuteOfDay: number
}

export const CalendarWeekView = React.memo(function CalendarWeekView(
  props: SharedViewProps & {
    minHour: number
    maxHour: number
  }
) {
  return (
    <CalendarTimeGridView
      {...props}
      days={getWeekDays(props.anchorDate, props.weekStartsOn, props.hiddenDays)}
    />
  )
})

export const CalendarDayView = React.memo(function CalendarDayView(
  props: SharedViewProps & {
    minHour: number
    maxHour: number
  }
) {
  return (
    <CalendarTimeGridView
      {...props}
      days={[startOfDay(getNextVisibleDay(props.anchorDate, props.hiddenDays))]}
    />
  )
})

function CalendarTimeGridView(props: TimeGridViewProps) {
  const [draft, setDraft] = React.useState<CalendarCreateDraft | null>(null)
  const [now, setNow] = React.useState(() => new Date())
  const scrollContainerRef = React.useRef<HTMLDivElement | null>(null)
  const dayGridRefs = React.useRef<Array<HTMLDivElement | null>>([])
  const minMinute = props.minHour * 60
  const maxMinute = props.maxHour * 60
  const totalMinutes = maxMinute - minMinute
  const slotCount = Math.max(1, totalMinutes / props.slotDuration)
  const gridHeight = slotCount * props.slotHeight
  const [focusedSlot, setFocusedSlot] = React.useState<FocusedTimeSlot>(() =>
    getDefaultFocusedTimeSlot(props.days, minMinute, maxMinute, props.slotDuration)
  )
  const [focusedGridDayIndex, setFocusedGridDayIndex] = React.useState<
    number | null
  >(null)
  const gridInstructionsId = React.useId()
  const commitDraft = React.useEffectEvent(() => {
    if (!draft || !props.onEventCreate) {
      return
    }

    const startMinute = Math.min(draft.startMinute, draft.endMinute)
    const endMinute = Math.max(draft.startMinute, draft.endMinute)
    const start = setMinuteOfDay(startOfDay(draft.day), startMinute)
    const end = setMinuteOfDay(
      startOfDay(draft.day),
      Math.min(endMinute + props.slotDuration, 1_440)
    )

    props.onEventCreate({
      start,
      end,
    })
    setDraft(null)
  })

  React.useEffect(() => {
    if (!draft) {
      return
    }

    function handlePointerUp() {
      commitDraft()
    }

    window.addEventListener("pointerup", handlePointerUp)

    return () => {
      window.removeEventListener("pointerup", handlePointerUp)
    }
  }, [draft])

  React.useEffect(() => {
    const intervalId = window.setInterval(() => {
      setNow(new Date())
    }, 30_000)

    return () => {
      window.clearInterval(intervalId)
    }
  }, [])

  React.useEffect(() => {
    const container = scrollContainerRef.current

    if (!container || !props.scrollToTime) {
      return
    }

    const currentDate = new Date()
    const targetMinute =
      props.scrollToTime === "now"
        ? currentDate.getHours() * 60 + currentDate.getMinutes()
        : parseTimeStringToMinuteOfDay(props.scrollToTime)

    if (targetMinute === null) {
      return
    }

    const clampedMinute = Math.min(maxMinute, Math.max(minMinute, targetMinute))
    const nextScrollTop = Math.max(
      0,
      ((clampedMinute - minMinute) / props.slotDuration) * props.slotHeight -
        props.slotHeight * 2
    )

    container.scrollTop = nextScrollTop
  }, [
    maxMinute,
    minMinute,
    props.scrollToTime,
    props.slotDuration,
    props.slotHeight,
  ])

  React.useEffect(() => {
    setFocusedSlot((currentSlot) =>
      normalizeFocusedTimeSlot(
        currentSlot,
        props.days.length,
        minMinute,
        maxMinute,
        props.slotDuration
      )
    )
  }, [maxMinute, minMinute, props.days.length, props.slotDuration])

  const allDayEventsByDay = React.useMemo(() => {
    return new Map(
      props.days.map((day) => [day.getTime(), getAllDayEvents(props.occurrences, day)])
    )
  }, [props.days, props.occurrences])

  const timedLayoutsByDay = React.useMemo(() => {
    return new Map(
      props.days.map((day) => [
        day.getTime(),
        getDayLayout(props.occurrences, day, minMinute, maxMinute),
      ])
    )
  }, [maxMinute, minMinute, props.days, props.occurrences])

  function focusDayGrid(dayIndex: number) {
    requestAnimationFrame(() => {
      dayGridRefs.current[dayIndex]?.focus()
    })
  }

  function handleGridKeyDown(
    dayIndex: number,
    day: Date,
    event: React.KeyboardEvent<HTMLDivElement>
  ) {
    if (event.altKey || event.ctrlKey || event.metaKey) {
      return
    }

    const currentMinuteOfDay = clampGridMinute(
      focusedSlot.minuteOfDay,
      minMinute,
      maxMinute,
      props.slotDuration
    )
    const maxDayIndex = Math.max(0, props.days.length - 1)
    let nextDayIndex = dayIndex
    let nextMinuteOfDay = currentMinuteOfDay
    let handled = true

    switch (event.key) {
      case "ArrowUp":
        nextMinuteOfDay = clampGridMinute(
          currentMinuteOfDay - props.slotDuration,
          minMinute,
          maxMinute,
          props.slotDuration
        )
        break
      case "ArrowDown":
        nextMinuteOfDay = clampGridMinute(
          currentMinuteOfDay + props.slotDuration,
          minMinute,
          maxMinute,
          props.slotDuration
        )
        break
      case "ArrowLeft":
        nextDayIndex = Math.max(0, dayIndex - 1)
        break
      case "ArrowRight":
        nextDayIndex = Math.min(maxDayIndex, dayIndex + 1)
        break
      case "Home":
        nextMinuteOfDay = minMinute
        break
      case "End":
        nextMinuteOfDay = clampGridMinute(
          maxMinute - props.slotDuration,
          minMinute,
          maxMinute,
          props.slotDuration
        )
        break
      case "Enter":
      case " ": {
        if (!props.onEventCreate) {
          return
        }

        event.preventDefault()
        const start = setMinuteOfDay(startOfDay(day), currentMinuteOfDay)
        const end = setMinuteOfDay(
          startOfDay(day),
          Math.min(currentMinuteOfDay + props.slotDuration, 1_440)
        )

        props.onEventCreate({
          end,
          start,
        })
        return
      }
      default:
        handled = false
        break
    }

    if (!handled) {
      return
    }

    event.preventDefault()
    setFocusedSlot({
      dayIndex: nextDayIndex,
      minuteOfDay: nextMinuteOfDay,
    })

    if (nextDayIndex !== dayIndex) {
      focusDayGrid(nextDayIndex)
    }
  }

  return (
    <div className="min-h-0 flex-1 overflow-auto" ref={scrollContainerRef}>
      <div className="min-w-4xl">
        <div
          className="grid border-b border-border/70"
          style={{
            gridTemplateColumns: `4.5rem repeat(${props.days.length}, minmax(0, 1fr))`,
          }}
        >
          <div
            className={cn(
              "border-r border-border/70 text-[11px] tracking-[0.24em] text-muted-foreground uppercase",
              props.density === "compact" ? "px-3 py-2.5" : "px-3 py-3"
            )}
          >
            Time
          </div>
          {props.days.map((day) => (
            <div
              key={`header-${day.toISOString()}`}
              className={getCalendarSlotClassName(
                props.classNames,
                "timeGridHeader",
                cn(
                  "border-r border-border/70 last:border-r-0",
                  props.density === "compact" ? "px-3 py-2.5" : "px-3 py-3"
                )
              )}
              id={getTimeGridHeaderId(day)}
            >
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-[11px] tracking-[0.24em] text-muted-foreground uppercase">
                    {formatWeekday(day, {
                      locale: props.locale,
                      timeZone: props.timeZone,
                    })}
                  </p>
                  <p className="text-sm font-medium">
                    {formatMonthDayLabel(day, {
                      locale: props.locale,
                      timeZone: props.timeZone,
                    })}
                  </p>
                </div>
                {isToday(day) ? (
                  <span className="rounded-full bg-primary/12 px-2 py-1 text-[11px] font-medium text-primary">
                    Today
                  </span>
                ) : null}
              </div>
            </div>
          ))}
        </div>
        <div
          className="grid border-b border-border/70"
          style={{
            gridTemplateColumns: `4.5rem repeat(${props.days.length}, minmax(0, 1fr))`,
          }}
        >
          <div
            className={cn(
              "border-r border-border/70 text-[11px] tracking-[0.24em] text-muted-foreground uppercase",
              props.density === "compact" ? "px-3 py-2.5" : "px-3 py-3"
            )}
          >
            All day
          </div>
          {props.days.map((day) => (
            <AllDayDropZone
              key={`all-day-${day.toISOString()}`}
              activeDropTarget={props.activeDropTarget}
              classNames={props.classNames}
              day={day}
              density={props.density}
              dragPreviewOccurrence={props.dragPreviewOccurrence}
              draggingOccurrenceId={props.draggingOccurrenceId}
              events={allDayEventsByDay.get(day.getTime()) ?? []}
              getEventColor={props.getEventColor}
              hourCycle={props.hourCycle}
              interactive={props.interactive}
              locale={props.locale}
              onEventDragPointerDown={props.onEventDragPointerDown}
              onEventKeyCommand={props.onEventKeyCommand}
              onOpenContextMenu={props.onOpenContextMenu}
              onSelect={props.onSelectEvent}
              previewOccurrenceId={props.previewOccurrenceId}
              renderEvent={props.renderEvent}
              selectedEventId={props.selectedEventId}
              shouldSuppressEventClick={props.shouldSuppressEventClick}
              timeZone={props.timeZone}
            />
          ))}
        </div>
        <p className="sr-only" id={gridInstructionsId}>
          Use arrow keys to move the active time slot. Use left and right arrows
          to change days.
          {props.onEventCreate
            ? " Press Enter or Space to create an event at the active slot."
            : ""}
        </p>
        <div
          className={getCalendarSlotClassName(
            props.classNames,
            "timeGrid",
            "grid"
          )}
          style={{
            gridTemplateColumns: `4.5rem repeat(${props.days.length}, minmax(0, 1fr))`,
          }}
        >
          <div className="relative border-r border-border/70">
            {Array.from({ length: slotCount }).map((_, index) => {
              const minute = minMinute + index * props.slotDuration
              const labelDate = setMinuteOfDay(
                startOfDay(props.days[0]),
                minute
              )

              return (
                <div
                  key={`time-label-${minute}`}
                  className="border-b border-border/50 px-3 text-[11px] text-muted-foreground"
                  style={{
                    height: props.slotHeight,
                  }}
                >
                  {minute % 60 === 0
                    ? (
                        <div className="space-y-0.5 pt-0.5">
                          <p>
                            {formatHourLabel(labelDate, {
                              hourCycle: props.hourCycle,
                              locale: props.locale,
                              timeZone: props.timeZone,
                            })}
                          </p>
                          {props.showSecondaryTimeZone &&
                          props.secondaryTimeZone ? (
                            <p className="text-[10px] text-muted-foreground/80">
                              {formatHourLabel(labelDate, {
                                hourCycle: props.hourCycle,
                                locale: props.locale,
                                timeZone: props.secondaryTimeZone,
                              })}
                            </p>
                          ) : null}
                        </div>
                      )
                    : null}
                </div>
              )
            })}
          </div>
          {props.days.map((day, dayIndex) => {
            const layout = timedLayoutsByDay.get(day.getTime()) ?? []
            const previewLayout = getTimeGridPreviewLayout(
              layout,
              props.dragPreviewOccurrence,
              day,
              minMinute,
              maxMinute
            )
            const currentMinuteOfDay = now.getHours() * 60 + now.getMinutes()
            const showNowIndicator =
              isSameDay(day, now) &&
              currentMinuteOfDay >= minMinute &&
              currentMinuteOfDay <= maxMinute
            const nowIndicatorTop =
              ((currentMinuteOfDay - minMinute) / totalMinutes) * gridHeight
            const headerId = getTimeGridHeaderId(day)
            const activeSlotId =
              focusedSlot.dayIndex === dayIndex
                ? getTimeGridSlotId(day, focusedSlot.minuteOfDay)
                : undefined

            return (
              <div
                key={`day-column-${day.toISOString()}`}
                className={getCalendarSlotClassName(
                  props.classNames,
                  "timeGridDayColumn",
                  "relative border-r border-border/70 last:border-r-0"
                )}
              >
                <div
                  aria-activedescendant={activeSlotId}
                  aria-colcount={1}
                  aria-describedby={gridInstructionsId}
                  aria-labelledby={headerId}
                  aria-rowcount={slotCount}
                  className="relative h-full outline-none focus-visible:ring-2 focus-visible:ring-inset focus-visible:ring-primary/35"
                  onBlur={(event) => {
                    if (
                      event.relatedTarget instanceof Node &&
                      event.currentTarget.contains(event.relatedTarget)
                    ) {
                      return
                    }

                    setFocusedGridDayIndex((currentIndex) =>
                      currentIndex === dayIndex ? null : currentIndex
                    )
                  }}
                  onFocus={() => {
                    setFocusedGridDayIndex(dayIndex)
                    setFocusedSlot((currentSlot) => ({
                      dayIndex,
                      minuteOfDay: clampGridMinute(
                        currentSlot.minuteOfDay,
                        minMinute,
                        maxMinute,
                        props.slotDuration
                      ),
                    }))
                  }}
                  onKeyDown={(event) => handleGridKeyDown(dayIndex, day, event)}
                  ref={(element) => {
                    dayGridRefs.current[dayIndex] = element
                  }}
                  role="grid"
                  style={{
                    height: gridHeight,
                  }}
                  tabIndex={focusedSlot.dayIndex === dayIndex ? 0 : -1}
                >
                  <TimeGridBackground
                    blockedRanges={props.blockedRanges}
                    businessHours={props.businessHours}
                    day={day}
                    gridHeight={gridHeight}
                    maxMinute={maxMinute}
                    minMinute={minMinute}
                    slotDuration={props.slotDuration}
                    slotHeight={props.slotHeight}
                  />
                  <div
                    className="absolute inset-0 grid"
                    style={{
                      gridTemplateRows: `repeat(${slotCount}, ${props.slotHeight}px)`,
                    }}
                  >
                    {Array.from({ length: slotCount }).map((_, index) => {
                      const minuteOfDay = minMinute + index * props.slotDuration
                      const slotStart = setMinuteOfDay(startOfDay(day), minuteOfDay)
                      const slotEnd = setMinuteOfDay(
                        startOfDay(day),
                        Math.min(minuteOfDay + props.slotDuration, 1_440)
                      )

                      return (
                        <div
                          key={`${day.toISOString()}-${minuteOfDay}`}
                          role="row"
                        >
                          <TimeSlotDropZone
                            active={
                              focusedSlot.dayIndex === dayIndex &&
                              focusedSlot.minuteOfDay === minuteOfDay
                            }
                            blocked={
                              props.blockedRanges?.some((range) =>
                                slotStart.getTime() < range.end.getTime() &&
                                slotEnd.getTime() > range.start.getTime()
                              ) ?? false
                            }
                            classNames={props.classNames}
                            day={day}
                            draft={draft}
                            focusVisible={focusedGridDayIndex === dayIndex}
                            hourCycle={props.hourCycle}
                            isDragTarget={
                              props.activeDropTarget?.kind === "slot" &&
                              props.activeDropTarget.day.getTime() === day.getTime() &&
                              props.activeDropTarget.minuteOfDay === minuteOfDay
                            }
                            locale={props.locale}
                            minuteOfDay={minuteOfDay}
                            onBeginCreate={() => {
                              if (!props.onEventCreate) {
                                return
                              }

                              setDraft({
                                day,
                                startMinute: minuteOfDay,
                                endMinute: minuteOfDay,
                              })
                            }}
                            onExtendCreate={() => {
                              if (!draft || !isSameDay(draft.day, day)) {
                                return
                              }

                              setDraft({
                                ...draft,
                                endMinute: minuteOfDay,
                              })
                            }}
                            onFocusCell={() => {
                              setFocusedGridDayIndex(dayIndex)
                              setFocusedSlot({
                                dayIndex,
                                minuteOfDay,
                              })
                              focusDayGrid(dayIndex)
                            }}
                            slotId={getTimeGridSlotId(day, minuteOfDay)}
                            timeZone={props.timeZone}
                          />
                        </div>
                      )
                    })}
                  </div>
                  {draft && isSameDay(draft.day, day) ? (
                    <div
                      className="pointer-events-none absolute inset-x-1 rounded-[calc(var(--radius)*0.9)] border border-dashed border-primary/60 bg-primary/10"
                      style={{
                        top:
                          ((Math.min(draft.startMinute, draft.endMinute) -
                            minMinute) /
                            props.slotDuration) *
                          props.slotHeight,
                        height:
                          ((Math.abs(draft.endMinute - draft.startMinute) +
                            props.slotDuration) /
                            props.slotDuration) *
                          props.slotHeight,
                      }}
                    >
                      {props.showCreatePreviewMeta ? (
                        <span className="absolute left-2 top-2 rounded-full bg-background/95 px-2 py-0.5 text-[10px] font-medium text-foreground shadow-xs">
                          {formatDraftRangeLabel(draft, {
                            day,
                            hourCycle: props.hourCycle,
                            locale: props.locale,
                            slotDuration: props.slotDuration,
                            timeZone: props.timeZone,
                          })}
                        </span>
                      ) : null}
                    </div>
                  ) : null}
                  {previewLayout ? (
                    <div
                      className="pointer-events-none absolute z-10 px-1"
                      style={{
                        top:
                          ((previewLayout.top - minMinute) / props.slotDuration) *
                          props.slotHeight,
                        height: Math.max(
                          props.slotHeight - 4,
                          (previewLayout.height / props.slotDuration) *
                            props.slotHeight
                        ),
                        left: `calc(${(previewLayout.column * 100) / previewLayout.columns}% + 0px)`,
                        width: `calc(${100 / previewLayout.columns}% - 0px)`,
                      }}
                    >
                      <div className="h-full rounded-[min(var(--radius-sm),4px)] border border-dashed border-foreground/18 bg-foreground/8 shadow-sm dark:border-white/12 dark:bg-white/8" />
                    </div>
                  ) : null}
                  {showNowIndicator ? (
                    <div
                      className="pointer-events-none absolute inset-x-0 z-20"
                      style={{
                        top: nowIndicatorTop,
                      }}
                    >
                      <div className="relative h-0">
                        <div className="absolute top-1/2 left-0 size-2.5 -translate-x-1/2 -translate-y-1/2 rounded-full bg-primary shadow-[0_0_0_3px_var(--color-background)]" />
                        <div className="h-0.5 w-full bg-primary" />
                      </div>
                    </div>
                  ) : null}
                  {layout.map((item, index) => {
                    const width = 100 / item.columns
                    const left = item.column * width

                    return (
                      <div
                        key={item.occurrence.occurrenceId}
                        className="absolute px-1"
                        style={{
                          top:
                            ((item.top - minMinute) / props.slotDuration) *
                            props.slotHeight,
                          height: Math.max(
                            props.slotHeight - 4,
                            (item.height / props.slotDuration) * props.slotHeight
                          ),
                          left: `calc(${left}% + 0px)`,
                          width: `calc(${width}% - 0px)`,
                        }}
                      >
                        <CalendarEventCard
                          accentColor={getResolvedAccentColor(
                            item.occurrence,
                            props.getEventColor,
                            index
                          )}
                          classNames={props.classNames}
                          density={props.density}
                          dragging={
                            props.draggingOccurrenceId === item.occurrence.occurrenceId
                          }
                          event={item.occurrence}
                          interactive={props.interactive}
                          onDragPointerDown={props.onEventDragPointerDown}
                          onEventKeyCommand={props.onEventKeyCommand}
                          onResizeHandlePointerDown={
                            props.onResizeHandlePointerDown
                          }
                          onOpenContextMenu={props.onOpenContextMenu}
                          onSelect={props.onSelectEvent}
                          preview={
                            props.previewOccurrenceId ===
                            item.occurrence.occurrenceId
                          }
                          renderEvent={props.renderEvent}
                          selected={
                            props.selectedEventId ===
                            item.occurrence.occurrenceId
                          }
                          showResizeHandles
                          shouldSuppressClick={props.shouldSuppressEventClick}
                          previewMetaLabel={
                            props.showDragPreviewMeta &&
                            props.previewOccurrenceId === item.occurrence.occurrenceId
                              ? formatDurationLabel(
                                  item.occurrence.start,
                                  item.occurrence.end,
                                  item.occurrence.allDay
                                )
                              : undefined
                          }
                          timeLabel={getEventMetaLabel(
                            item.occurrence,
                            {
                              hourCycle: props.hourCycle,
                              locale: props.locale,
                              timeZone: props.timeZone,
                            }
                          )}
                          variant="time-grid"
                        />
                      </div>
                    )
                  })}
                </div>
              </div>
            )
          })}
        </div>
      </div>
    </div>
  )
}

function TimeGridBackground({
  blockedRanges,
  businessHours,
  day,
  gridHeight,
  maxMinute,
  minMinute,
  slotDuration,
  slotHeight,
}: {
  blockedRanges: TimeGridViewProps["blockedRanges"]
  businessHours: TimeGridViewProps["businessHours"]
  day: Date
  gridHeight: number
  maxMinute: number
  minMinute: number
  slotDuration: number
  slotHeight: number
}) {
  const outsideBusinessHourSegments = getOutsideBusinessHourSegmentsForDay(
    day,
    businessHours,
    minMinute,
    maxMinute
  )
  const businessHourSegments = getBusinessHourSegmentsForDay(
    day,
    businessHours,
    minMinute,
    maxMinute
  )
  const blockedSegments = getBlockedSegmentsForDay(
    day,
    blockedRanges,
    minMinute,
    maxMinute
  )

  return (
    <div className="pointer-events-none absolute inset-0">
      {outsideBusinessHourSegments.map((segment) => (
        <div
          key={`outside-${segment.startMinute}-${segment.endMinute}`}
          className="absolute inset-x-0 bg-muted/20"
          style={{
            height:
              ((segment.endMinute - segment.startMinute) / slotDuration) *
              slotHeight,
            top:
              ((segment.startMinute - minMinute) / slotDuration) * slotHeight,
          }}
        />
      ))}
      {businessHourSegments.map((segment) => (
        <div
          key={`business-${segment.startMinute}-${segment.endMinute}`}
          className="absolute inset-x-0 border-y border-primary/10 bg-primary/3"
          style={{
            height:
              ((segment.endMinute - segment.startMinute) / slotDuration) *
              slotHeight,
            top:
              ((segment.startMinute - minMinute) / slotDuration) * slotHeight,
          }}
        />
      ))}
      {blockedSegments.map((segment) => (
        <div
          key={segment.id}
          className="absolute inset-x-1 rounded-[calc(var(--radius)*0.7)] border"
          style={{
            backgroundColor: `${segment.color ?? "#be185d"}14`,
            borderColor: `${segment.color ?? "#be185d"}33`,
            height:
              ((segment.endMinute - segment.startMinute) / slotDuration) *
              slotHeight,
            top:
              ((segment.startMinute - minMinute) / slotDuration) * slotHeight,
          }}
        >
          {segment.label ? (
            <span
              className="absolute left-2 top-1 rounded-full px-1.5 py-0.5 text-[10px] font-medium"
              style={{
                backgroundColor: `${segment.color ?? "#be185d"}22`,
                color: segment.color ?? "#be185d",
              }}
            >
              {segment.label}
            </span>
          ) : null}
        </div>
      ))}
      <div className="absolute inset-0 shadow-[inset_0_1px_0_0_var(--color-border)]" />
      <div
        className="absolute inset-x-0 bottom-0 border-b border-border/50"
        style={{ top: gridHeight - 1 }}
      />
    </div>
  )
}

