                    <input
                      checked={formState.allDay}
                      className="size-4 accent-primary"
                      onChange={(event) =>
                        updateFormState("allDay", event.target.checked)
                      }
                      type="checkbox"
                    />
                    <span>
                      <span className="block text-sm font-medium">All-day event</span>
                      <span className="block text-xs text-muted-foreground">
                        Hide time inputs and keep the event pinned to full days.
                      </span>
                    </span>
                  </label>
                  <div className="space-y-2">
                    <Label htmlFor="calendar-details-resource">Calendar</Label>
                    <select
                      className={selectClassName}
                      id="calendar-details-resource"
                      onChange={(event) =>
                        updateFormState("resourceId", event.target.value)
                      }
                      value={formState.resourceId}
                    >
                      {resources?.length ? (
                        resources.map((item) => (
                          <option key={item.id} value={item.id}>
                            {item.label}
                          </option>
                        ))
                      ) : (
                        <option value="">Default calendar</option>
                      )}
                    </select>
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="calendar-details-location">Location</Label>
                    <Input
                      id="calendar-details-location"
                      onChange={(event) =>
                        updateFormState("location", event.target.value)
                      }
                      placeholder="Remote"
                      value={formState.location}
                    />
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="calendar-details-description">
                      Description
                    </Label>
                    <Textarea
                      id="calendar-details-description"
                      onChange={(event) =>
                        updateFormState("description", event.target.value)
                      }
                      placeholder="Agenda, notes, or attendee details."
                      value={formState.description}
                    />
                  </div>
                </section>
              ) : (
                <section className="space-y-4">
                  {occurrence.location ? (
                    <SummaryBlock icon={MapPinIcon} label="Location">
                      {occurrence.location}
                    </SummaryBlock>
                  ) : null}
                  {occurrence.description ? (
                    <SummaryBlock icon={NotePencilIcon} label="Notes">
                      {occurrence.description}
                    </SummaryBlock>
                  ) : null}
                  <SummaryBlock icon={ClockIcon} label="Schedule">
                    {formatEventTimeLabel(occurrence.start, occurrence.end, {
                      allDay: occurrence.allDay,
                      hourCycle,
                      locale,
                      timeZone: primaryTimeZone,
                    })}
                  </SummaryBlock>
                  {secondaryTimeZone ? (
                    <SummaryBlock icon={ClockIcon} label="Secondary timezone">
                      {formatEventTimeLabel(occurrence.start, occurrence.end, {
                        allDay: occurrence.allDay,
                        hourCycle,
                        locale,
                        timeZone: secondaryTimeZone,
                      })}
                    </SummaryBlock>
                  ) : null}
                  {resource ? (
                    <SummaryBlock icon={StackIcon} label="Calendar">
                      {resource.label}
                    </SummaryBlock>
                  ) : null}
                  {occurrence.isRecurringInstance ? (
                    <p className="rounded-[calc(var(--radius)*0.9)] border border-border/70 bg-muted/25 px-3 py-2 text-sm text-muted-foreground">
                      This occurrence belongs to a recurring series. Built-in
                      editing updates the source series event.
                    </p>
                  ) : null}
                  {!occurrence.location && !occurrence.description ? (
                    <p className="rounded-[calc(var(--radius)*0.9)] border border-dashed border-border/70 px-3 py-4 text-sm text-muted-foreground">
                      No description or location has been added yet.
                    </p>
                  ) : null}
                </section>
              )}

              {error ? (
                <p className="rounded-[calc(var(--radius)*0.9)] border border-destructive/30 bg-destructive/5 px-3 py-2 text-sm text-destructive">
                  {error}
                </p>
              ) : null}
            </div>

            <div className="sticky bottom-0 border-t border-border/70 bg-background px-6 py-4">
              <div className="flex flex-wrap justify-end gap-2">
                {isEditing ? (
                  <>
                    <Button
                      onClick={() => {
                        setError(undefined)
                        setIsEditing(false)
                      }}
                      type="button"
                      variant="outline"
                    >
                      {cancelLabel}
                    </Button>
                    <Button
                      data-testid="calendar-event-details-submit"
                      type="submit"
                    >
                      {submitLabel}
                    </Button>
                  </>
                ) : (
                  <>
                    <Button
                      onClick={() => onOpenChange(false)}
                      type="button"
                      variant="outline"
                    >
                      {closeLabel}
                    </Button>
                    {canEdit ? (
                      <Button
                        data-testid="calendar-event-details-edit"
                        onClick={(event) => {
                          event.preventDefault()
                          event.stopPropagation()
                          setError(undefined)
                          setIsEditing(true)
                        }}
                        type="button"
                      >
                        <PencilSimpleIcon className="size-4" />
                        {editLabel}
                      </Button>
                    ) : null}
                  </>
                )}
              </div>
            </div>
          </form>
        )}
      </aside>
    </div>
  )
}

function SummaryBlock({
  children,
  icon: Icon,
  label,
}: {
  children: React.ReactNode
  icon: React.ComponentType<{ className?: string }>
  label: string
}) {
  return (
    <div className="rounded-[calc(var(--radius)*0.95)] border border-border/70 bg-muted/25 px-3 py-3">
      <p className="inline-flex items-center gap-2 text-xs tracking-[0.18em] text-muted-foreground uppercase">
        <Icon className="size-3.5" />
        {label}
      </p>
      <p className="mt-2 text-sm leading-6 text-foreground whitespace-pre-wrap">
        {children}
      </p>
    </div>
  )
}

function InfoPill({
  children,
  icon: Icon,
}: {
  children: React.ReactNode
  icon?: React.ComponentType<{ className?: string }>
}) {
  return (
    <span className="inline-flex items-center gap-1 rounded-full border border-border/70 bg-muted/35 px-2.5 py-1">
      {Icon ? <Icon className="size-3.5" /> : null}
      {children}
    </span>
  )
}

function buildDateTime(dateValue: string, timeValue: string) {
  const normalizedTime = timeValue || "00:00"

  return new Date(`${dateValue}T${normalizedTime}:00`)
}

function normalizeOptionalText(value: string) {
  const trimmedValue = value.trim()

  return trimmedValue.length > 0 ? trimmedValue : undefined
}

const selectClassName = cn(
  "flex h-10 w-full rounded-md border border-input bg-background px-3 py-2 text-sm shadow-xs transition-[color,box-shadow] outline-none",
  "focus-visible:border-ring focus-visible:ring-[3px] focus-visible:ring-ring/50"
)

"use client"

import * as React from "react"

import { KeyboardIcon } from "@phosphor-icons/react"

import { Button } from "@/components/ui/button"

import type { CalendarKeyboardShortcutsConfig } from "../../types"
import { useModalFocus } from "./use-modal-focus"

type CalendarKeyboardShortcutsDialogProps = {
  config?: CalendarKeyboardShortcutsConfig
  onOpenChange: (open: boolean) => void
  open: boolean
}

const shortcutRows = [
  {
    description: "Move the active schedule slot through the week or day grid.",
    keys: "Arrow keys in grid",
  },
  {
    description: "Create from the active schedule slot.",
    keys: "Enter / Space",
  },
  {
    description: "Move the selected event in time or across days.",
    keys: "Arrow keys on event",
  },
  {
    description: "Resize the selected event from the end.",
    keys: "Shift + Arrow keys",
  },
  {
    description: "Resize the selected event from the start.",
    keys: "Alt + Arrow keys",
  },
  {
    description: "Open the event context menu.",
    keys: "Shift + F10",
  },
  {
    description: "Open this shortcut dialog when enabled.",
    keys: "?",
  },
]

export function CalendarKeyboardShortcutsDialog({
  config,
  onOpenChange,
  open,
}: CalendarKeyboardShortcutsDialogProps) {
  const dialogRef = React.useRef<HTMLDivElement | null>(null)
  const titleId = React.useId()
  const descriptionId = React.useId()

  useModalFocus({
    containerRef: dialogRef,
    onClose: () => onOpenChange(false),
    open,
  })

  if (!open) {
    return null
  }

  const title =
    typeof config === "object"
      ? config.title ?? "Keyboard shortcuts"
      : "Keyboard shortcuts"
  const description =
    typeof config === "object"
      ? config.description ??
        "Use the keyboard to nudge, resize, and inspect events without leaving the current view."
      : "Use the keyboard to nudge, resize, and inspect events without leaving the current view."

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/45 px-4 py-6 backdrop-blur-sm">
      <button
        aria-label="Close keyboard shortcuts"
        className="absolute inset-0"
        onClick={() => onOpenChange(false)}
        type="button"
      />
      <div
        aria-describedby={descriptionId}
        aria-labelledby={titleId}
        aria-modal="true"
        className="relative z-10 w-[min(100%-2rem,32rem)] rounded-[calc(var(--radius)*1.2)] border border-border/80 bg-background p-5 shadow-[0_32px_90px_-40px_rgba(15,23,42,0.65)] outline-none"
        data-testid="calendar-keyboard-shortcuts-dialog"
        ref={dialogRef}
        role="dialog"
        tabIndex={-1}
      >
        <div className="flex items-start gap-3">
          <div className="inline-flex size-10 shrink-0 items-center justify-center rounded-[calc(var(--radius)*0.85)] bg-primary/10 text-primary">
            <KeyboardIcon className="size-5" />
          </div>
          <div className="min-w-0 flex-1">
            <h2 className="text-base font-semibold tracking-tight" id={titleId}>
              {title}
            </h2>
            <p
              className="mt-1 text-sm leading-6 text-muted-foreground"
              id={descriptionId}
            >
              {description}
            </p>
          </div>
        </div>
        <div className="mt-5 space-y-2">
          {shortcutRows.map((row) => (
            <div
              key={row.keys}
              className="grid gap-2 rounded-[calc(var(--radius)*0.95)] border border-border/70 bg-muted/25 px-3 py-3 sm:grid-cols-[10rem_1fr] sm:items-center"
            >
              <p className="font-mono text-sm font-medium text-foreground">
                {row.keys}
              </p>
              <p className="text-sm leading-6 text-muted-foreground">
                {row.description}
              </p>
            </div>
          ))}
        </div>

        <div className="mt-5 flex justify-end">
          <Button onClick={() => onOpenChange(false)} variant="outline">
            Close
          </Button>
        </div>
      </div>
    </div>
  )
}
